import BrandGallery from "./BrandGallery";
import { PHOTOS } from "../data/photos";

const studioPhotos = PHOTOS.filter((photo) => ["wedding", "portrait"].includes(photo.category)).slice(0, 9);

export default function AyyanStudioGallery({ onBack }) {
  return (
    <BrandGallery
      title="Ayyan Studio"
      subtitle="Studio portraits, editorial celebrations and elegant family sessions captured with heart."
      photos={studioPhotos}
      onBack={onBack}
    />
  );
}
